#!/usr/bin/env node

/**
 * @catpaw/token-exchange — CatPaw SSO Token Exchange CLI
 *
 * Standalone Node.js script invoked by SSO SDK during skill token exchange.
 * SSO SDK spawns this via: bash -lc "npx catpaw-token-exchange --audience_cipher <encrypted>"
 * Optionally pass --baseurl <url> to override the default backend (https://catpaw.sankuai.com).
 * Optionally pass --token <sso_token> to supply the SSO token directly (skips config file read).
 *
 * Flow:
 * 1. Parse --audience_cipher argument
 * 2. Read AES-256 key K from env var CATDESK_SSO_AGENT_KEY
 * 3. Decrypt audience_cipher → { ok: true, audience: "xxA xxB xxC" }
 * 4. Read SSO token from ~/.catpaw/sso_config.json (ssoid field)
 * 5. POST <baseurl>/api/oauth/token-exchange with { accessToken, audience }
 * 6. Output standardized JSON on stdout
 *
 * Contract (stdout JSON):
 * {
 *   "code": 0,           // 0 = success, 1001 = not logged in
 *   "message": "...",
 *   "data": {
 *     "access_token": "AT_xxx",
 *     "token_type": "Bearer",
 *     "expires_in": 10800,
 *     "issued_token_type": "urn:ietf:params:oauth:token-type:access_token"
 *   }
 * }
 *
 * All diagnostic logs go to stderr (never stdout — SSO SDK parses stdout).
 * Zero external dependencies — only Node.js built-in modules.
 *
 * @see https://km.sankuai.com/collabpage/2752828433
 */

'use strict'

const crypto = require('node:crypto')
const https = require('node:https')
const http = require('node:http')
const fs = require('node:fs')
const path = require('node:path')
const os = require('node:os')

// ==================== Constants ====================

const IV_LENGTH = 12
const AUTH_TAG_LENGTH = 16
const KEY_ENV_VAR = 'CATDESK_SSO_AGENT_KEY'

